import{_ as a,o,c as r,ag as t}from"./chunks/framework.YaIgwL5o.js";const c=JSON.parse('{"title":"Shapes & Drawing","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/shapes-drawing.md","filePath":"tutorials/shapes-drawing.md"}'),i={name:"tutorials/shapes-drawing.md"};function s(n,e,l,d,h,p){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="shapes-drawing" tabindex="-1">Shapes &amp; Drawing <a class="header-anchor" href="#shapes-drawing" aria-label="Permalink to &quot;Shapes &amp; Drawing&quot;">​</a></h1><p>This tutorial covers shape elements, freehand drawing, non-objective compositions, and modular grids.</p><h2 id="inserting-shapes" tabindex="-1">Inserting shapes <a class="header-anchor" href="#inserting-shapes" aria-label="Permalink to &quot;Inserting shapes&quot;">​</a></h2><ol><li>Click the <strong>Shapes</strong> dropdown in the toolbar.</li><li>Choose from: <strong>Rectangle</strong>, <strong>Rounded Rectangle</strong>, <strong>Circle</strong>, <strong>Triangle</strong>, <strong>Diamond</strong>, <strong>Arrow</strong>, <strong>Star</strong>, or <strong>Line</strong>.</li><li>The shape appears on the slide. Drag to reposition, drag handles to resize.</li></ol><h2 id="shape-properties" tabindex="-1">Shape properties <a class="header-anchor" href="#shape-properties" aria-label="Permalink to &quot;Shape properties&quot;">​</a></h2><p>Select a shape to configure in the right panel:</p><ul><li><strong>Fill</strong> — color picker, or &quot;none&quot; for transparent</li><li><strong>Stroke</strong> — border color and width</li><li><strong>Opacity</strong> — 0 (transparent) to 1 (fully opaque)</li><li><strong>Text</strong> — add a label inside the shape</li><li><strong>Round Corners</strong> — border radius for rectangles</li></ul><h3 id="example-output" tabindex="-1">Example output <a class="header-anchor" href="#example-output" aria-label="Permalink to &quot;Example output&quot;">​</a></h3><div style="border:1px solid #333;border-radius:8px;overflow:hidden;margin:16px 0;"><iframe src="/revealjs_gui/demos/shapes.html" style="width:100%;height:140px;border:none;"></iframe></div><h2 id="freehand-drawing" tabindex="-1">Freehand drawing <a class="header-anchor" href="#freehand-drawing" aria-label="Permalink to &quot;Freehand drawing&quot;">​</a></h2><ol><li>Click the <strong>Pencil</strong> icon in the toolbar to enter draw mode.</li><li>Choose a color and stroke width from the drawing toolbar.</li><li>Draw directly on the slide canvas.</li><li>Click the pencil icon again (or press <code>Escape</code>) to exit draw mode.</li></ol><p>Drawn strokes are SVG elements that can be selected, moved, and deleted like any other element.</p><h2 id="non-objective-compositions" tabindex="-1">Non-objective compositions <a class="header-anchor" href="#non-objective-compositions" aria-label="Permalink to &quot;Non-objective compositions&quot;">​</a></h2><p>Inspired by Bauhaus and De Stijl, these insert randomized geometric compositions.</p><ol><li>Click <strong>Shapes</strong> &gt; <strong>Non-objective</strong> in the toolbar.</li><li>A composition of overlapping geometric forms appears.</li><li>Each shape can be individually selected and edited.</li></ol><h2 id="modular-grid" tabindex="-1">Modular grid <a class="header-anchor" href="#modular-grid" aria-label="Permalink to &quot;Modular grid&quot;">​</a></h2><p>Creates a grid of identical shapes as a structural framework.</p><ol><li>Click <strong>Shapes</strong> &gt; <strong>Modular Grid</strong>.</li><li>Configure the number of columns, rows, gap size, and shape type.</li><li>Click <strong>Apply</strong> — a grid of shapes fills the slide.</li><li>Assign content to individual cells as needed.</li></ol>',18)])])}const u=a(i,[["render",s]]);export{c as __pageData,u as default};
